function transform(message, context) {
  function esc(value) {
    if (value === null || value === undefined) return "";
    return String(value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  function tryParseJson(value) {
    if (value === null || value === undefined) return value;
    if (typeof value !== "string") return value;
    var t = String(value).trim();
    if (t === "") return value;
    if ((t.charAt(0) === "{" && t.charAt(t.length - 1) === "}") || (t.charAt(0) === "[" && t.charAt(t.length - 1) === "]")) {
      try {
        return JSON.parse(t);
      } catch (e) {
        return value;
      }
    }
    return value;
  }

  function isRowObject(obj) {
    if (!obj || typeof obj !== "object" || Array.isArray(obj)) return false;
    var keys = Object.keys(obj);
    if (keys.length === 0) return false;
    if (obj.header !== undefined || obj.__type !== undefined || obj.statusText !== undefined || obj.runId !== undefined) return false;
    return true;
  }

  function collectRows(node, rows) {
    var parsed;
    var i;
    if (node === null || node === undefined) return;
    parsed = tryParseJson(node);
    if (parsed !== node) {
      collectRows(parsed, rows);
      return;
    }
    if (Array.isArray(node)) {
      for (i = 0; i < node.length; i++) collectRows(node[i], rows);
      return;
    }
    if (typeof node === "object") {
      if (node.data !== undefined) collectRows(node.data, rows);
      if (node.payload !== undefined) collectRows(node.payload, rows);
      if (node.postResponse !== undefined) collectRows(node.postResponse, rows);
      if (node.records !== undefined) collectRows(node.records, rows);
      if (node.items !== undefined) collectRows(node.items, rows);
      if (isRowObject(node)) rows.push(node);
    }
  }

  function uniqueHeadersFromAllRows(rows) {
    var seen = {};
    var headers = [];
    var i;
    var j;
    var keys;
    var k;
    for (i = 0; i < rows.length; i++) {
      keys = Object.keys(rows[i] || {});
      for (j = 0; j < keys.length; j++) {
        k = keys[j];
        if (!seen[k]) {
          seen[k] = true;
          headers.push(k);
        }
      }
    }
    return headers;
  }

  try {
    var rows = [];
    var headers = [];
    var theadHtml = "";
    var tbodyHtml = "";
    var html = "";
    var i;
    var j;

    collectRows(message, rows);

    if ((!rows || rows.length === 0) && message && message.payload !== undefined) {
      collectRows(message.payload, rows);
    }

    if (!rows || rows.length === 0) {
      message.payload =
        "<html><body><h3>No usable records found in incoming data.</h3><pre>" +
        esc(typeof message.payload === "string" ? message.payload : JSON.stringify(message.payload, null, 2)) +
        "</pre></body></html>";
      return message;
    }

    headers = uniqueHeadersFromAllRows(rows);

    if (headers.indexOf("Comment") < 0) {
      headers.push("Comment");
    }

    var maxRecords = rows.length;

    if (
      context &&
      context.Number_of_Records !== null &&
      context.Number_of_Records !== undefined &&
      String(context.Number_of_Records).trim() !== ""
    ) {
      var parsedMax = parseInt(context.Number_of_Records, 10);
      if (!isNaN(parsedMax) && parsedMax > 0 && parsedMax < rows.length) {
        maxRecords = parsedMax;
      }
    }

    theadHtml += "<tr id='headerRow'>";

    for (i = 0; i < headers.length; i++) {
      theadHtml +=
        "<th data-col-index='" + i + "'>" +
          "<div class='thWrap'>" +
            "<span class='headerText' data-original='" + esc(headers[i]) + "' title='Double click to edit heading'>" + esc(headers[i]) + "</span>" +
            "<button type='button' class='moveLeftMiniBtn' data-col-index='" + i + "' title='Move this column left'>←</button>" +
            "<button type='button' class='moveRightMiniBtn' data-col-index='" + i + "' title='Move this column right'>→</button>" +
            "<button type='button' class='sortMiniBtn' data-col-index='" + i + "' title='Sort this column'>↕</button>" +
            "<button type='button' class='hideMiniBtn' data-col-index='" + i + "' title='Hide this column'>×</button>" +
          "</div>" +
        "</th>";
    }

    theadHtml += "</tr>";

    for (i = 0; i < maxRecords; i++) {
      tbodyHtml += "<tr tabindex='0' data-row-index='" + i + "'>";

      for (j = 0; j < headers.length; j++) {
        var fieldName = headers[j];
        var fieldValue = "";

        if (fieldName === "Comment") {
          tbodyHtml +=
            "<td class='commentCell'>" +
              "<div class='commentInline'>" +
                "<textarea class='commentText' placeholder='Speech text...' title='Recorded speech text appears here'></textarea>" +
                "<button type='button' class='commentBtn'>🎤 Record</button>" +
                "<button type='button' class='stopBtn'>■ Stop</button>" +
                "<audio class='commentAudio' controls></audio>" +
                "<a class='audioLink' href='' download='comment-audio.webm' target='_blank'>Audio link will appear here</a>" +
              "</div>" +
            "</td>";
        } else {
          if (rows[i] && rows[i][fieldName] !== null && rows[i][fieldName] !== undefined) {
            if (typeof rows[i][fieldName] === "object") {
              fieldValue = JSON.stringify(rows[i][fieldName]);
            } else {
              fieldValue = rows[i][fieldName];
            }
          }
          tbodyHtml += "<td>" + esc(fieldValue) + "</td>";
        }
      }

      tbodyHtml += "</tr>";
    }

    var reportName = context && context.Heading_Text ? context.Heading_Text : "Universal SaaS Data Query Report";
    var dbName = context && (context.__stage || context.env || context.tenant)
      ? (context.__stage || context.env || context.tenant)
      : "";
    var sqlText = context && context.SQLstatement ? context.SQLstatement : "";
    var reportType = context && context.ReportType ? context.ReportType : "";
    var numToPrint = context && context.Number_of_Records ? context.Number_of_Records : "";
    var pageNumber = context && context.PageNumber ? context.PageNumber : "1";
    var pdfFileName = reportName.replace(/[^a-zA-Z0-9_ -]/g, "").replace(/\s+/g, "_") || "report";

    var appScript = [
      "var sortDirections = {};",
      "var currentRowIndex = -1;",
      "var activeRecorder = null;",
      "var activeRecognition = null;",
      "var activeVoiceRecognition = null;",
      "var activeStream = null;",
      "var activeChunks = [];",
      "var activeButton = null;",

      "function qs(s){return document.querySelector(s);}",
      "function qsa(s){return Array.prototype.slice.call(document.querySelectorAll(s));}",
      "function getBodyRows(){return qsa('#recordTable tr');}",
      "function getHeaderCells(){return qsa('#reportTable thead th');}",
      "function getHeaderText(index){var h=getHeaderCells()[index];if(!h)return '';var span=h.querySelector('.headerText');return span?String(span.innerText||span.textContent||'').trim():String(h.innerText||h.textContent||'').trim();}",
      "function getCellValue(row,index){if(!row||!row.cells||!row.cells[index])return '';var cell=row.cells[index];var t=cell.querySelector('textarea');if(t)return t.value||'';return cell.innerText||cell.textContent||'';}",

      "function escapeHtml(value){if(value===null||value===undefined)return '';return String(value).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\"/g,'&quot;').replace(/'/g,'&#39;');}",
      "function canonicalText(value){var s=String(value||'');s=s.replace(/([a-z])([A-Z])/g,'$1 $2');s=s.toLowerCase();s=s.replace(/&nbsp;/g,' ');s=s.replace(/[_\\-\\/\\.]+/g,' ');s=s.replace(/[^a-z0-9 ]/g,' ');s=s.replace(/\\s+/g,' ').trim();return s;}",
      "function compactText(value){return canonicalText(value).replace(/\\s+/g,'');}",
      "function removeCommandWords(value){var s=canonicalText(value);s=s.replace(/\\b(column|field|value|named|name|the|please|by|for|with|called|heading|header)\\b/g,' ');s=s.replace(/\\s+/g,' ').trim();return s;}",
      "function toInitCap(value){var s=String(value||'').toLowerCase().replace(/[_\\-\\/\\.]+/g,' ').replace(/\\s+/g,' ').trim();if(s==='')return '';return s.split(' ').map(function(w){return w?w.charAt(0).toUpperCase()+w.slice(1):'';}).join(' ');}",

      "function findColumnIndexByName(name){var wanted=removeCommandWords(name);var wantedCompact=compactText(wanted);var headers=getHeaderCells();var bestIndex=-1;var bestScore=0;for(var i=0;i<headers.length;i++){var hClean=removeCommandWords(getHeaderText(i));var hCompact=compactText(hClean);if(!wantedCompact||!hCompact)continue;if(hCompact===wantedCompact||hClean===wanted)return i;var score=0;if(hCompact.indexOf(wantedCompact)>=0||wantedCompact.indexOf(hCompact)>=0){score=90;}else{var wTokens=wanted.split(' ');var hTokens=hClean.split(' ');var matches=0;for(var a=0;a<wTokens.length;a++){for(var b=0;b<hTokens.length;b++){if(wTokens[a]&&hTokens[b]&&(wTokens[a]===hTokens[b]||hTokens[b].indexOf(wTokens[a])>=0||wTokens[a].indexOf(hTokens[b])>=0)){matches++;break;}}}score=Math.round((matches/Math.max(wTokens.length,1))*80);}if(score>bestScore){bestScore=score;bestIndex=i;}}return bestScore>=45?bestIndex:-1;}",

      "function updateSearchStats(visible,total){var a=qs('#totalRecordsBox');var b=qs('#totalFieldsBox');var c=qs('#filteredRowsBox');if(a)a.textContent=total;if(b)b.textContent=getHeaderCells().length;if(c)c.textContent=visible;}",
