      "function startVoiceCommand(){var SR=window.SpeechRecognition||window.webkitSpeechRecognition;var btn=qs('#voiceCommandBtn');if(!SR){alert('Voice Command works in Chrome or Edge only.');return;}try{if(activeVoiceRecognition){activeVoiceRecognition.stop();activeVoiceRecognition=null;}}catch(e){}activeVoiceRecognition=new SR();activeVoiceRecognition.lang='en-US';activeVoiceRecognition.interimResults=false;activeVoiceRecognition.continuous=false;activeVoiceRecognition.maxAlternatives=1;if(btn){btn.classList.add('listening');btn.innerHTML='🎤 Listening...';}setVoiceStatus('Listening for command...');activeVoiceRecognition.onresult=function(event){var spoken=event.results&&event.results[0]&&event.results[0][0]?event.results[0][0].transcript:'';runVoiceCommand(spoken);};activeVoiceRecognition.onerror=function(event){setVoiceStatus('Voice command error: '+event.error);alert('Voice command error: '+event.error);};activeVoiceRecognition.onend=function(){if(btn){btn.classList.remove('listening');btn.innerHTML='🎤 Voice Command';}activeVoiceRecognition=null;};activeVoiceRecognition.start();}",

      "function runVoiceCommand(spoken){var original=String(spoken||'').trim();var cmd=canonicalText(original);setVoiceStatus('Command heard: '+original);if(cmd==='')return;if(cmd==='clear'||cmd==='clear search'||cmd==='clear search criteria'||cmd==='reset search'||cmd==='show all records'||cmd==='show all'){clearReportSearch();setVoiceStatus('Executed: Clear search criteria');return;}if(cmd.indexOf('change heading')===0||cmd.indexOf('change report heading')===0||cmd.indexOf('change title')===0){var headingText='';var m1=original.match(/^\\s*change\\s+(?:report\\s+)?(?:heading|title)\\s+(?:by|to|as)\\s+(.+)$/i);if(m1&&m1[1])headingText=m1[1].trim();else headingText=original.replace(/^\\s*change\\s+(?:report\\s+)?(?:heading|title)\\s*/i,'').replace(/^\\s*(by|to|as)\\s+/i,'').trim();changeReportHeading(headingText);return;}if(cmd.indexOf('change field')===0||cmd.indexOf('change column')===0){var temp=original.replace(/^\\s*change\\s+(?:field|column)\\s+(?:heading|header|name)?\\s*/i,'').trim();var pair=splitVoiceByKeyword(temp,[' by ',' to ',' as ']);if(pair&&pair.left&&pair.right){changeFieldHeading(pair.left,pair.right);return;}alert('Please say: Change field name Address by Home Address');setVoiceStatus('Unable to understand field heading change command.');return;}if(cmd.indexOf('rename field')===0||cmd.indexOf('rename column')===0){var temp2=original.replace(/^\\s*rename\\s+(?:field|column)\\s*/i,'').trim();var pair2=splitVoiceByKeyword(temp2,[' by ',' to ',' as ']);if(pair2&&pair2.left&&pair2.right){changeFieldHeading(pair2.left,pair2.right);return;}alert('Please say: Rename field Address to Home Address');setVoiceStatus('Unable to understand field rename command.');return;}if(cmd.indexOf('export csv')>=0||cmd.indexOf('download csv')>=0){exportVisibleCsv();setVoiceStatus('Executed: Export CSV');return;}if(cmd.indexOf('generate pdf')>=0||cmd.indexOf('create pdf')>=0||cmd.indexOf('export pdf')>=0||cmd.indexOf('convert to pdf')>=0||cmd.indexOf('convert pdf')>=0){convertToPdf();setVoiceStatus('Executed: Convert to PDF');return;}if(cmd.indexOf('sort by ')===0){var sortCol=cmd.replace(/^sort by\\s+/,'');var sortIdx=findColumnIndexByName(sortCol);if(sortIdx>=0){sortTable(sortIdx);setVoiceStatus('Executed: Sort by '+getHeaderText(sortIdx));}else{alert('Column not found: '+sortCol);setVoiceStatus('Column not found: '+sortCol);}return;}if(cmd.indexOf('hide column ')===0||cmd.indexOf('hide field ')===0){var hideCol=cmd.replace(/^hide\\s+(column|field)\\s+/,'');var hideIdx=findColumnIndexByName(hideCol);if(hideIdx>=0){deleteColumn(hideIdx);setVoiceStatus('Executed: Hide column '+hideCol);}else{alert('Column not found: '+hideCol);setVoiceStatus('Column not found: '+hideCol);}return;}if(cmd.indexOf('search ')===0||cmd.indexOf('find ')===0){var phrase=cmd.replace(/^(search|find)\\s+/,'').trim();if(phrase.indexOf(' in ')>0){var parts=phrase.split(' in ');var val=parts[0].trim();var col=parts.slice(1).join(' in ').trim();var idx=findColumnIndexByName(col);if(idx>=0){searchColumnValue(idx,val);setVoiceStatus('Executed: Search '+getHeaderText(idx)+' for '+val);return;}}var bestCol=-1;var bestWords=0;var bestValue='';for(var i=0;i<getHeaderCells().length;i++){var h=canonicalText(getHeaderText(i));if(phrase.indexOf(h+' ')===0&&h.split(' ').length>bestWords){bestCol=i;bestWords=h.split(' ').length;bestValue=phrase.substring(h.length).trim();}}if(bestCol>=0&&bestValue){searchColumnValue(bestCol,bestValue);setVoiceStatus('Executed: Search '+getHeaderText(bestCol)+' for '+bestValue);return;}var input=qs('#reportSearchInput');if(input)input.value=phrase;searchReportTable();setVoiceStatus('Executed: Search all fields for '+phrase);return;}alert('Unknown command: '+original+'\\n\\nSupported examples:\\nExport CSV\\nGenerate PDF\\nConvert to PDF\\nClear\\nChange Heading by Student Report\\nChange Field Name Address by Home Address\\nSearch Ryan\\nSearch Last Name Ryan\\nSearch Ryan in Last Name\\nSort by Last Name\\nHide column Email');}",

