      "function qs(s){return document.querySelector(s);}",
      "function qsa(s){return Array.prototype.slice.call(document.querySelectorAll(s));}",
      "function getBodyRows(){return qsa('#recordTable tr');}",
      "function getHeaderCells(){return qsa('#reportTable thead th');}",
      "function getHeaderText(index){var h=getHeaderCells()[index];if(!h)return '';var span=h.querySelector('.headerText');return span?String(span.innerText||span.textContent||'').trim():String(h.innerText||h.textContent||'').trim();}",
      "function getCellValue(row,index){if(!row||!row.cells||!row.cells[index])return '';var cell=row.cells[index];var t=cell.querySelector('textarea');if(t)return t.value||'';return cell.innerText||cell.textContent||'';}",

      "function escapeHtml(value){if(value===null||value===undefined)return '';return String(value).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\"/g,'&quot;').replace(/'/g,'&#39;');}",
      "function canonicalText(value){var s=String(value||'');s=s.replace(/([a-z])([A-Z])/g,'$1 $2');s=s.toLowerCase();s=s.replace(/&nbsp;/g,' ');s=s.replace(/[_\\-\\/\\.]+/g,' ');s=s.replace(/[^a-z0-9 ]/g,' ');s=s.replace(/\\s+/g,' ').trim();return s;}",
      "function compactText(value){return canonicalText(value).replace(/\\s+/g,'');}",
      "function removeCommandWords(value){var s=canonicalText(value);s=s.replace(/\\b(column|field|value|named|name|the|please|by|for|with|called|heading|header)\\b/g,' ');s=s.replace(/\\s+/g,' ').trim();return s;}",
      "function toInitCap(value){var s=String(value||'').toLowerCase().replace(/[_\\-\\/\\.]+/g,' ').replace(/\\s+/g,' ').trim();if(s==='')return '';return s.split(' ').map(function(w){return w?w.charAt(0).toUpperCase()+w.slice(1):'';}).join(' ');}",

      "function findColumnIndexByName(name){var wanted=removeCommandWords(name);var wantedCompact=compactText(wanted);var headers=getHeaderCells();var bestIndex=-1;var bestScore=0;for(var i=0;i<headers.length;i++){var hClean=removeCommandWords(getHeaderText(i));var hCompact=compactText(hClean);if(!wantedCompact||!hCompact)continue;if(hCompact===wantedCompact||hClean===wanted)return i;var score=0;if(hCompact.indexOf(wantedCompact)>=0||wantedCompact.indexOf(hCompact)>=0){score=90;}else{var wTokens=wanted.split(' ');var hTokens=hClean.split(' ');var matches=0;for(var a=0;a<wTokens.length;a++){for(var b=0;b<hTokens.length;b++){if(wTokens[a]&&hTokens[b]&&(wTokens[a]===hTokens[b]||hTokens[b].indexOf(wTokens[a])>=0||wTokens[a].indexOf(hTokens[b])>=0)){matches++;break;}}}score=Math.round((matches/Math.max(wTokens.length,1))*80);}if(score>bestScore){bestScore=score;bestIndex=i;}}return bestScore>=45?bestIndex:-1;}",

      "function updateSearchStats(visible,total){var a=qs('#totalRecordsBox');var b=qs('#totalFieldsBox');var c=qs('#filteredRowsBox');if(a)a.textContent=total;if(b)b.textContent=getHeaderCells().length;if(c)c.textContent=visible;}",
      "function getRowSearchText(row){var text=String(row.innerText||row.textContent||'');var inputs=row.querySelectorAll('input,textarea');for(var i=0;i<inputs.length;i++){text+=' '+String(inputs[i].value||inputs[i].getAttribute('data-comment')||'');}return text.toLowerCase();}",
      "function searchReportTable(){var input=qs('#reportSearchInput');var info=qs('#searchInfo');var q=input?String(input.value||'').toLowerCase().trim():'';var rows=getBodyRows();var visible=0;for(var i=0;i<rows.length;i++){var text=getRowSearchText(rows[i]);if(q===''||text.indexOf(q)>=0){rows[i].style.display='';visible++;}else{rows[i].style.display='none';}}if(info){info.textContent=q===''?'Showing all records.':'Showing '+visible+' matching record(s) out of '+rows.length+'.';}var rc=qs('#recordCount');if(rc)rc.textContent=visible;updateSearchStats(visible,rows.length);}",
      "function searchColumnValue(colIndex,value){var info=qs('#searchInfo');var q=canonicalText(value);var rows=getBodyRows();var visible=0;for(var i=0;i<rows.length;i++){var cellText=canonicalText(getCellValue(rows[i],colIndex));if(q===''||cellText.indexOf(q)>=0){rows[i].style.display='';visible++;}else{rows[i].style.display='none';}}if(info){info.textContent='Showing '+visible+' matching record(s) where '+getHeaderText(colIndex)+' contains: '+value;}var rc=qs('#recordCount');if(rc)rc.textContent=visible;updateSearchStats(visible,rows.length);}",
      "function clearReportSearch(){var input=qs('#reportSearchInput');if(input)input.value='';searchReportTable();if(input)input.focus();}",
      "function setVoiceStatus(msg){var s=qs('#voiceCommandStatus');if(s)s.textContent=msg;}",

      "function startTypedHeaderEdit(event,span){if(event){event.preventDefault();event.stopPropagation();}if(!span)return;span.contentEditable='true';span.classList.add('editing');span.focus();try{var range=document.createRange();range.selectNodeContents(span);range.collapse(false);var sel=window.getSelection();if(sel){sel.removeAllRanges();sel.addRange(range);}}catch(e){}}",
      "function finishTypedHeaderEdit(span){if(!span)return;if(span.contentEditable!=='true')return;var v=String(span.innerText||span.textContent||'').replace(/\\n/g,' ').replace(/\\s+/g,' ').trim();if(v==='')v=span.getAttribute('data-original')||'Field';span.textContent=v;span.setAttribute('data-original',v);span.contentEditable='false';span.classList.remove('editing');refreshHeaderIndexes();setVoiceStatus('Field heading changed to '+v);}",
      "function headerEditKeydown(event,span){if(event&&event.key==='Enter'){event.preventDefault();if(span)span.blur();}if(event&&event.key==='Escape'){event.preventDefault();if(span){span.textContent=span.getAttribute('data-original')||span.textContent;span.contentEditable='false';span.classList.remove('editing');span.blur();}}}",
      "function attachHeaderEditHandlers(){qsa('.headerText').forEach(function(span){span.contentEditable='false';span.onclick=function(e){e.stopPropagation();};span.ondblclick=function(e){startTypedHeaderEdit(e,span);};span.onblur=function(){finishTypedHeaderEdit(span);};span.onkeydown=function(e){headerEditKeydown(e,span);};});}",

      "function changeReportHeading(newHeading){newHeading=toInitCap(String(newHeading||'').trim());if(newHeading===''){alert('Please say the new heading. Example: Change Heading by Student Report');return;}var h=qs('#reportHeading')||qs('.reportTitle');if(h){h.textContent=newHeading;setVoiceStatus('Executed: Changed report heading to '+newHeading);}else{alert('Report heading was not found.');setVoiceStatus('Report heading was not found.');}}",
      "function changeFieldHeading(oldHeading,newHeading){oldHeading=String(oldHeading||'').trim();newHeading=toInitCap(String(newHeading||'').trim());if(oldHeading===''||newHeading===''){alert('Please say old and new field heading. Example: Change field name Address by Home Address');return;}var idx=findColumnIndexByName(oldHeading);if(idx<0){alert('Field heading not found: '+oldHeading);setVoiceStatus('Field heading not found: '+oldHeading);return;}var span=getHeaderCells()[idx].querySelector('.headerText');if(span){span.textContent=newHeading;span.setAttribute('data-original',newHeading);}refreshHeaderIndexes();setVoiceStatus('Executed: Changed field heading '+oldHeading+' to '+newHeading);}",
      "function splitVoiceByKeyword(original,keywords){var lower=String(original||'').toLowerCase();for(var i=0;i<keywords.length;i++){var k=keywords[i];var pos=lower.indexOf(k);if(pos>=0)return {left:String(original).substring(0,pos).trim(),right:String(original).substring(pos+k.length).trim(),keyword:k};}return null;}",

      "function startVoiceCommand(){var SR=window.SpeechRecognition||window.webkitSpeechRecognition;var btn=qs('#voiceCommandBtn');if(!SR){alert('Voice Command works in Chrome or Edge only.');return;}try{if(activeVoiceRecognition){activeVoiceRecognition.stop();activeVoiceRecognition=null;}}catch(e){}activeVoiceRecognition=new SR();activeVoiceRecognition.lang='en-US';activeVoiceRecognition.interimResults=false;activeVoiceRecognition.continuous=false;activeVoiceRecognition.maxAlternatives=1;if(btn){btn.classList.add('listening');btn.innerHTML='🎤 Listening...';}setVoiceStatus('Listening for command...');activeVoiceRecognition.onresult=function(event){var spoken=event.results&&event.results[0]&&event.results[0][0]?event.results[0][0].transcript:'';runVoiceCommand(spoken);};activeVoiceRecognition.onerror=function(event){setVoiceStatus('Voice command error: '+event.error);alert('Voice command error: '+event.error);};activeVoiceRecognition.onend=function(){if(btn){btn.classList.remove('listening');btn.innerHTML='🎤 Voice Command';}activeVoiceRecognition=null;};activeVoiceRecognition.start();}",

      "function runVoiceCommand(spoken){var original=String(spoken||'').trim();var cmd=canonicalText(original);setVoiceStatus('Command heard: '+original);if(cmd==='')return;if(cmd==='clear'||cmd==='clear search'||cmd==='clear search criteria'||cmd==='reset search'||cmd==='show all records'||cmd==='show all'){clearReportSearch();setVoiceStatus('Executed: Clear search criteria');return;}if(cmd.indexOf('change heading')===0||cmd.indexOf('change report heading')===0||cmd.indexOf('change title')===0){var headingText='';var m1=original.match(/^\\s*change\\s+(?:report\\s+)?(?:heading|title)\\s+(?:by|to|as)\\s+(.+)$/i);if(m1&&m1[1])headingText=m1[1].trim();else headingText=original.replace(/^\\s*change\\s+(?:report\\s+)?(?:heading|title)\\s*/i,'').replace(/^\\s*(by|to|as)\\s+/i,'').trim();changeReportHeading(headingText);return;}if(cmd.indexOf('change field')===0||cmd.indexOf('change column')===0){var temp=original.replace(/^\\s*change\\s+(?:field|column)\\s+(?:heading|header|name)?\\s*/i,'').trim();var pair=splitVoiceByKeyword(temp,[' by ',' to ',' as ']);if(pair&&pair.left&&pair.right){changeFieldHeading(pair.left,pair.right);return;}alert('Please say: Change field name Address by Home Address');setVoiceStatus('Unable to understand field heading change command.');return;}if(cmd.indexOf('rename field')===0||cmd.indexOf('rename column')===0){var temp2=original.replace(/^\\s*rename\\s+(?:field|column)\\s*/i,'').trim();var pair2=splitVoiceByKeyword(temp2,[' by ',' to ',' as ']);if(pair2&&pair2.left&&pair2.right){changeFieldHeading(pair2.left,pair2.right);return;}alert('Please say: Rename field Address to Home Address');setVoiceStatus('Unable to understand field rename command.');return;}if(cmd.indexOf('export csv')>=0||cmd.indexOf('download csv')>=0){exportVisibleCsv();setVoiceStatus('Executed: Export CSV');return;}if(cmd.indexOf('generate pdf')>=0||cmd.indexOf('create pdf')>=0||cmd.indexOf('export pdf')>=0||cmd.indexOf('convert to pdf')>=0||cmd.indexOf('convert pdf')>=0){convertToPdf();setVoiceStatus('Executed: Convert to PDF');return;}if(cmd.indexOf('create column before ')===0){var beforeCol=cmd.replace(/^create column before\s+/,'');insertColumnRelative(beforeCol,'before');return;}if(cmd.indexOf('create column after ')===0){var afterCol=cmd.replace(/^create column after\s+/,'');insertColumnRelative(afterCol,'after');return;}if(cmd.indexOf('sort by ')===0){var sortCol=cmd.replace(/^sort by\\s+/,'');var sortIdx=findColumnIndexByName(sortCol);if(sortIdx>=0){sortTable(sortIdx);setVoiceStatus('Executed: Sort by '+getHeaderText(sortIdx));}else{alert('Column not found: '+sortCol);setVoiceStatus('Column not found: '+sortCol);}return;}if(cmd.indexOf('hide column ')===0||cmd.indexOf('hide field ')===0){var hideCol=cmd.replace(/^hide\\s+(column|field)\\s+/,'');var hideIdx=findColumnIndexByName(hideCol);if(hideIdx>=0){deleteColumn(hideIdx);setVoiceStatus('Executed: Hide column '+hideCol);}else{alert('Column not found: '+hideCol);setVoiceStatus('Column not found: '+hideCol);}return;}if(cmd.indexOf('search ')===0||cmd.indexOf('find ')===0){var phrase=cmd.replace(/^(search|find)\\s+/,'').trim();if(phrase.indexOf(' in ')>0){var parts=phrase.split(' in ');var val=parts[0].trim();var col=parts.slice(1).join(' in ').trim();var idx=findColumnIndexByName(col);if(idx>=0){searchColumnValue(idx,val);setVoiceStatus('Executed: Search '+getHeaderText(idx)+' for '+val);return;}}var bestCol=-1;var bestWords=0;var bestValue='';for(var i=0;i<getHeaderCells().length;i++){var h=canonicalText(getHeaderText(i));if(phrase.indexOf(h+' ')===0&&h.split(' ').length>bestWords){bestCol=i;bestWords=h.split(' ').length;bestValue=phrase.substring(h.length).trim();}}if(bestCol>=0&&bestValue){searchColumnValue(bestCol,bestValue);setVoiceStatus('Executed: Search '+getHeaderText(bestCol)+' for '+bestValue);return;}var input=qs('#reportSearchInput');if(input)input.value=phrase;searchReportTable();setVoiceStatus('Executed: Search all fields for '+phrase);return;}alert('Unknown command: '+original+'\\n\\nSupported examples:\\nExport CSV\\nGenerate PDF\\nConvert to PDF\\nClear\\nChange Heading by Student Report\\nChange Field Name Address by Home Address\\nSearch Ryan\\nSearch Last Name Ryan\\nSearch Ryan in Last Name\\nSort by Last Name\\nHide column Email');}",

      "function blobToDataUrl(blob,callback){var reader=new FileReader();reader.onloadend=function(){callback(reader.result);};reader.readAsDataURL(blob);}",
      "function saveAudioIntoCell(td,dataUrl){var audio=td.querySelector('.commentAudio');var link=td.querySelector('.audioLink');if(audio){audio.src=dataUrl;audio.setAttribute('src',dataUrl);}if(link){link.href=dataUrl;link.setAttribute('href',dataUrl);link.textContent='Play / Download Recorded Audio';link.setAttribute('download','comment-audio.webm');}td.setAttribute('data-audio',dataUrl);}",
      "function stopCommentRecording(){try{if(activeRecognition){try{activeRecognition.stop();}catch(e){}}if(activeRecorder&&activeRecorder.state!=='inactive')activeRecorder.stop();if(activeStream){activeStream.getTracks().forEach(function(t){t.stop();});}if(activeButton){activeButton.classList.remove('recording');activeButton.innerHTML='🎤 Record Comment';}}catch(e){}}",
      "function recordComment(btn){var SR=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SR){alert('Speech recognition works in Chrome or Edge only.');return;}if(!navigator.mediaDevices||!navigator.mediaDevices.getUserMedia){alert('Audio recording requires a browser with microphone support.');return;}var td=btn.closest('td');var txt=td?td.querySelector('.commentText'):null;if(!td||!txt)return;activeButton=btn;activeChunks=[];btn.classList.add('recording');btn.innerHTML='Listening / Recording...';navigator.mediaDevices.getUserMedia({audio:true}).then(function(stream){activeStream=stream;activeRecorder=new MediaRecorder(stream);activeRecorder.ondataavailable=function(e){if(e.data&&e.data.size>0)activeChunks.push(e.data);};activeRecorder.onstop=function(){var blob=new Blob(activeChunks,{type:'audio/webm'});blobToDataUrl(blob,function(dataUrl){saveAudioIntoCell(td,dataUrl);syncValuesBeforeSave();searchReportTable();});if(activeStream){activeStream.getTracks().forEach(function(t){t.stop();});activeStream=null;}if(activeButton){activeButton.classList.remove('recording');activeButton.innerHTML='🎤 Record Comment';activeButton=null;}};activeRecorder.start();activeRecognition=new SR();activeRecognition.lang='en-US';activeRecognition.interimResults=false;activeRecognition.continuous=false;activeRecognition.maxAlternatives=1;activeRecognition.onresult=function(event){var spoken=event.results[0][0].transcript;txt.value=spoken;txt.defaultValue=spoken;txt.setAttribute('data-comment',spoken);txt.innerHTML=escapeHtml(spoken);};activeRecognition.onerror=function(event){alert('Voice text error: '+event.error);};activeRecognition.onend=function(){setTimeout(function(){if(activeRecorder&&activeRecorder.state!=='inactive')activeRecorder.stop();},500);};activeRecognition.start();}).catch(function(err){btn.classList.remove('recording');btn.innerHTML='🎤 Record Comment';alert('Microphone error: '+err);});}",

      "function syncValuesBeforeSave(){qsa('textarea').forEach(function(t){var v=t.value||'';t.defaultValue=v;t.setAttribute('data-comment',v);t.innerHTML=escapeHtml(v);});qsa('input').forEach(function(i){i.setAttribute('value',i.value||'');});qsa('audio.commentAudio').forEach(function(a){if(a.src)a.setAttribute('src',a.src);});qsa('a.audioLink').forEach(function(l){if(l.href){l.setAttribute('href',l.href);if(l.href.indexOf('data:audio')===0)l.textContent='Play / Download Recorded Audio';}});}",
      "function csvCell(v){return '\"'+String(v===null||v===undefined?'':v).replace(/\"/g,'\"\"')+'\"';}",
      "function exportVisibleCsv(){syncValuesBeforeSave();var headers=getHeaderCells().map(function(th){var span=th.querySelector('.headerText');return span?span.innerText:th.innerText;});var rows=getBodyRows().filter(function(r){return r.style.display!=='none';});var csv=headers.map(csvCell).join(',')+'\\n';for(var i=0;i<rows.length;i++){var cells=Array.prototype.slice.call(rows[i].cells);csv+=cells.map(function(td){var t=td.querySelector('textarea');var link=td.querySelector('a.audioLink');var audioText=link&&link.href&&link.href.indexOf('data:audio')===0?' Audio Link Saved':'';return csvCell(t?(t.value+audioText):(td.innerText||td.textContent||''));}).join(',')+'\\n';}var blob=new Blob([csv],{type:'text/csv;charset=utf-8;'});var url=URL.createObjectURL(blob);var a=document.createElement('a');a.href=url;a.download='" + esc(pdfFileName) + ".csv';document.body.appendChild(a);a.click();document.body.removeChild(a);setTimeout(function(){URL.revokeObjectURL(url);},1000);}",
      "function parseSortableValue(value){if(value===null||value===undefined)return {type:'string',value:''};var v=String(value).trim();if(v==='')return {type:'string',value:''};var numericText=v.replace(/,/g,'');var num=parseFloat(numericText);if(!isNaN(num)&&/^-?\\d+(\\.\\d+)?$/.test(numericText))return {type:'number',value:num};var date=new Date(v);if(!isNaN(date.getTime()))return {type:'date',value:date.getTime()};return {type:'string',value:v.toLowerCase()};}",
      "function moveColumn(fromIndex,toIndex){var table=qs('#reportTable');if(!table)return;var headerCount=getHeaderCells().length;if(fromIndex<0||toIndex<0||fromIndex>=headerCount||toIndex>=headerCount||fromIndex===toIndex)return;var rows=Array.prototype.slice.call(table.rows);for(var r=0;r<rows.length;r++){var row=rows[r];var cells=Array.prototype.slice.call(row.children);var moving=cells[fromIndex];var target=cells[toIndex];if(!moving||!target)continue;if(toIndex<fromIndex){row.insertBefore(moving,target);}else{row.insertBefore(moving,target.nextSibling);}}refreshHeaderIndexes();attachHeaderActions();attachHeaderEditHandlers();attachCommentActions();attachRowHandlers();searchReportTable();}",
      "function createEmptyCommentCell(){var td=document.createElement('td');td.className='commentCell';td.innerHTML=\"<div class='commentCompactLine'><textarea class='commentText' placeholder='Speech text...'></textarea><button type='button' class='commentBtn'>\ud83c\udfa4 Record Comment</button><button type='button' class='stopBtn'>\u25a0 Stop</button></div><audio class='commentAudio' controls></audio><a class='audioLink' href='' download='comment-audio.webm' target='_blank'>Audio</a>\";return td;}",
      "function createEmptyNormalCell(){var td=document.createElement('td');td.contentEditable='true';td.innerHTML='';return td;}",
      "function insertColumnAt(index,newHeaderName){var table=qs('#reportTable');var headerRow=qs('#headerRow');if(!table||!headerRow)return;var headerCount=getHeaderCells().length;if(index<0)index=0;if(index>headerCount)index=headerCount;var cleanName=toInitCap(newHeaderName||'New Column');var th=document.createElement('th');th.setAttribute('data-col-index',index);th.innerHTML=\"<div class='thWrap'><span class='headerText' data-original='\"+escapeHtml(cleanName)+\"' title='Double click to edit heading'>\"+escapeHtml(cleanName)+\"</span><button type='button' class='moveLeftMiniBtn' data-col-index='\"+index+\"' title='Move column left'>\u2190</button><button type='button' class='moveRightMiniBtn' data-col-index='\"+index+\"' title='Move column right'>\u2192</button><button type='button' class='sortMiniBtn' data-col-index='\"+index+\"' title='Sort this column'>\u2195</button><button type='button' class='insertMiniBtn' data-col-index='\"+index+\"' title='Create new column before this column'>\uff0b</button><button type='button' class='hideMiniBtn' data-col-index='\"+index+\"' title='Hide this column'>\u00d7</button></div>\";if(index>=headerRow.children.length){headerRow.appendChild(th);}else{headerRow.insertBefore(th,headerRow.children[index]);}var bodyRows=getBodyRows();for(var r=0;r<bodyRows.length;r++){var td=createEmptyNormalCell();if(index>=bodyRows[r].children.length){bodyRows[r].appendChild(td);}else{bodyRows[r].insertBefore(td,bodyRows[r].children[index]);}}refreshHeaderIndexes();attachHeaderActions();attachHeaderEditHandlers();attachRowHandlers();searchReportTable();setVoiceStatus('Created new column: '+cleanName);}",
      "function insertColumnRelative(fieldName,position){var idx=findColumnIndexByName(fieldName);if(idx<0){alert('Column not found: '+fieldName);setVoiceStatus('Column not found: '+fieldName);return;}var insertAt=position==='after'?idx+1:idx;insertColumnAt(insertAt,'New Column');}",
