    }

    headers = uniqueHeadersFromAllRows(rows);

    if (headers.indexOf("Comment") < 0) {
      headers.push("Comment");
    }

    var maxRecords = rows.length;

    if (
      context &&
      context.Number_of_Records !== null &&
      context.Number_of_Records !== undefined &&
      String(context.Number_of_Records).trim() !== ""
    ) {
      var parsedMax = parseInt(context.Number_of_Records, 10);
      if (!isNaN(parsedMax) && parsedMax > 0 && parsedMax < rows.length) {
        maxRecords = parsedMax;
      }
    }

    theadHtml += "<tr id='headerRow'>";

    for (i = 0; i < headers.length; i++) {
      theadHtml +=
        "<th data-col-index='" + i + "'>" +
          "<div class='thWrap'>" +
            "<span class='headerText' data-original='" + esc(headers[i]) + "' title='Double click to edit heading'>" + esc(headers[i]) + "</span>" +
            "<button type='button' class='moveLeftMiniBtn' data-col-index='" + i + "' title='Move column left'>←</button>" +
            "<button type='button' class='moveRightMiniBtn' data-col-index='" + i + "' title='Move column right'>→</button>" +
            "<button type='button' class='sortMiniBtn' data-col-index='" + i + "' title='Sort this column'>↕</button>" +
            "<button type='button' class='insertMiniBtn' data-col-index='" + i + "' title='Create new column before this column'>＋</button>" +
            "<button type='button' class='hideMiniBtn' data-col-index='" + i + "' title='Hide this column'>×</button>" +
          "</div>" +
        "</th>";
    }

    theadHtml += "</tr>";

    for (i = 0; i < maxRecords; i++) {
