      "function runVoiceCommand(spoken){var original=String(spoken||'').trim();var cmd=canonicalText(original);setVoiceStatus('Command heard: '+original);if(cmd==='')return;if(cmd==='clear'||cmd==='clear search'||cmd==='clear search criteria'||cmd==='reset search'||cmd==='show all records'||cmd==='show all'){clearReportSearch();setVoiceStatus('Executed: Clear search criteria');return;}if(cmd.indexOf('change heading')===0||cmd.indexOf('change report heading')===0||cmd.indexOf('change title')===0){var headingText='';var m1=original.match(/^\\s*change\\s+(?:report\\s+)?(?:heading|title)\\s+(?:by|to|as)\\s+(.+)$/i);if(m1&&m1[1])headingText=m1[1].trim();else headingText=original.replace(/^\\s*change\\s+(?:report\\s+)?(?:heading|title)\\s*/i,'').replace(/^\\s*(by|to|as)\\s+/i,'').trim();changeReportHeading(headingText);return;}if(cmd.indexOf('change field')===0||cmd.indexOf('change column')===0){var temp=original.replace(/^\\s*change\\s+(?:field|column)\\s+(?:heading|header|name)?\\s*/i,'').trim();var pair=splitVoiceByKeyword(temp,[' by ',' to ',' as ']);if(pair&&pair.left&&pair.right){changeFieldHeading(pair.left,pair.right);return;}alert('Please say: Change field name Address by Home Address');setVoiceStatus('Unable to understand field heading change command.');return;}if(cmd.indexOf('rename field')===0||cmd.indexOf('rename column')===0){var temp2=original.replace(/^\\s*rename\\s+(?:field|column)\\s*/i,'').trim();var pair2=splitVoiceByKeyword(temp2,[' by ',' to ',' as ']);if(pair2&&pair2.left&&pair2.right){changeFieldHeading(pair2.left,pair2.right);return;}alert('Please say: Rename field Address to Home Address');setVoiceStatus('Unable to understand field rename command.');return;}if(cmd.indexOf('make a graph')>=0||cmd.indexOf('make graph')>=0||cmd.indexOf('create graph')>=0||cmd.indexOf('make chart')>=0||cmd.indexOf('create chart')>=0||cmd.indexOf('pie chart')>=0||cmd.indexOf('bar chart')>=0){openGraphModal();var typeSel=qs('#graphTypeSelect');if(typeSel&&cmd.indexOf('